const contactForm=document.getElementById("contact-form");contactForm&&contactForm.addEventListener("submit",async e=>{e.preventDefault();const s=document.getElementById("honeypot").value;if(s!==""){console.warn("Spam détecté !");return}const t=document.getElementById("response-msg"),n=contactForm.querySelector("button");t.innerText="Envoi en cours...",t.className="text-muted small mt-3 text-center";const o={name:document.getElementById("name").value,email:document.getElementById("email").value,message:document.getElementById("message").value};try{const e=await fetch("https://hugo-contact.mcugnolio-662.workers.dev",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(o)});e.ok?(t.textContent="Merci pour votre message.",t.className="contact-success-msg",n&&n.classList.add("hidden"),contactForm.reset()):(t.textContent="Erreur lors de l'envoi. Réessayez plus tard.",t.className="contact-error-msg")}catch{t.textContent="Impossible de joindre le serveur.",t.className="contact-error-msg"}})